// Page 1 - Island Selection - Dũng
import React, { useState } from 'react';
import EarthMap from '../components/EarthMap';
import IslandCard from '../components/IslandCard';
import './Page1.css';

const Page1 = () => {
  const [selectedIsland, setSelectedIsland] = useState(null);

  const handleIslandClick = (island) => {
    setSelectedIsland(island);
    // Navigate to Page 2 with island filter
    console.log(`Selected island: ${island}`);
  };

  return (
    <div className="page1-container">
      {/* Header */}
      <header className="page1-header">
        <h1>🐧 Palmer Archipelago Penguins</h1>
        <p>Explore three islands in Antarctica and discover their penguin populations</p>
      </header>

      {/* Earth Map Component */}
      <EarthMap />

      {/* Island Selection Section */}
      <section className="island-selection">
        <h2>Select an Island to Explore</h2>
        <div className="island-cards-container">
          <IslandCard 
            island="Biscoe" 
            onClick={() => handleIslandClick('Biscoe')}
          />
          <IslandCard 
            island="Dream" 
            onClick={() => handleIslandClick('Dream')}
          />
          <IslandCard 
            island="Torgersen" 
            onClick={() => handleIslandClick('Torgersen')}
          />
        </div>
      </section>

      {/* Footer */}
      <footer className="page1-footer">
        <p>Team: Duy, Phúc, Dũng, Hung | COMP4010 Project</p>
      </footer>
    </div>
  );
};

export default Page1;
